import React, { memo, useMemo } from 'react';
import GameBoard from './GameBoard';
import GameTimer from './GameTimer';
import { useI18n } from '../i18n/I18nContext';

const BattleField = memo(({
    isMyTurn,
    opponentName,
    handleForfeit,
    dispPlayer,
    dispOpponent,
    handleShoot,
    explosionCells,
    noop,
    playerTimeLeft,
    turnStartedAt,
    myId,
    currentTurn,
    spectatorCount,
    isSpectator,
    lastShot,
    handleLeave,
    mySunkCount,
    theirSunkCount,
}) => {
    const { t } = useI18n();
    // Memoize filtered props to avoid breaking child React.memo
    const playerExplosions = useMemo(() => explosionCells.filter(e => e.board === 'player'), [explosionCells]);
    const opponentExplosions = useMemo(() => explosionCells.filter(e => e.board === 'opponent'), [explosionCells]);
    const playerLastShot = useMemo(() => lastShot?.board === 'player' ? lastShot : null, [lastShot]);
    const opponentLastShot = useMemo(() => lastShot?.board === 'opponent' ? lastShot : null, [lastShot]);

    return (
        <div className="space-y-3 sm:space-y-4 animate-fade-in">
            {playerTimeLeft && Object.keys(playerTimeLeft).length > 0 && (
                <GameTimer
                    playerTimeLeft={playerTimeLeft}
                    turnStartedAt={turnStartedAt}
                    currentTurn={currentTurn}
                    myId={myId}
                    opponentName={opponentName}
                />
            )}

            <div className={`glass-card p-3 sm:p-4 text-center transition-all relative overflow-hidden
                ${isSpectator
                    ? 'border-purple-500/30'
                    : isMyTurn
                        ? 'border-emerald-500/30 your-turn-card'
                        : 'border-slate-700/50'
                }`}>
                {isMyTurn && !isSpectator && <div className="absolute inset-0 bg-gradient-to-r from-emerald-500/5 via-transparent to-emerald-500/5 animate-pulse" />}
                <div className="flex items-center justify-between gap-2 relative">
                    <div className="flex-1 min-w-0 text-left">
                        <p className="text-sm sm:text-base font-black truncate">
                            {isSpectator
                                ? t('battle.spectating')
                                : isMyTurn ? t('battle.yourTurn') : t('battle.opTurn', opponentName)}
                        </p>
                        {!isSpectator && isMyTurn && <p className="text-[0.65rem] text-emerald-300/60">{t('battle.extraShot')}</p>}
                    </div>
                    <div className="flex items-center gap-1.5 shrink-0">
                        {spectatorCount > 0 && (
                            <span className="px-2 py-1 bg-purple-900/30 text-purple-300 text-[0.65rem] font-semibold rounded-lg border border-purple-700/30">
                                👁️ {spectatorCount}
                            </span>
                        )}
                        <button
                            onClick={isSpectator ? handleLeave : handleForfeit}
                            className="px-2.5 py-1.5 text-red-400/70 hover:text-red-300 hover:bg-red-500/10 text-xs font-semibold rounded-lg transition"
                            title={isSpectator ? t('battle.leaveTooltip') : t('battle.surrenderTooltip')}
                        >
                            {isSpectator ? t('battle.leave') : '🏳️'}
                        </button>
                    </div>
                </div>
            </div>

            {/* Ship scoreboard */}
            {!isSpectator && (mySunkCount > 0 || theirSunkCount > 0) && (
                <div className="flex items-center justify-center gap-4 text-xs">
                    <div className="flex items-center gap-1.5">
                        <span className="text-emerald-400 font-bold">{t('battle.yourHits') || 'Your hits'}</span>
                        <div className="flex gap-0.5">
                            {Array.from({ length: 5 }, (_, i) => (
                                <span key={i} className={`w-2 h-2 rounded-full transition-all ${i < mySunkCount ? 'bg-orange-400 shadow-sm shadow-orange-400/50' : 'bg-slate-700'}`} />
                            ))}
                        </div>
                    </div>
                    <span className="text-slate-600">│</span>
                    <div className="flex items-center gap-1.5">
                        <div className="flex gap-0.5">
                            {Array.from({ length: 5 }, (_, i) => (
                                <span key={i} className={`w-2 h-2 rounded-full transition-all ${i < theirSunkCount ? 'bg-red-500 shadow-sm shadow-red-500/50' : 'bg-slate-700'}`} />
                            ))}
                        </div>
                        <span className="text-red-400 font-bold">{t('battle.theirHits') || 'Their hits'}</span>
                    </div>
                </div>
            )}

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4 md:gap-6">
                <div className={`glass-card p-3 sm:p-4 transition-all animate-board-entry ${isSpectator ? '' : isMyTurn ? '' : 'border-yellow-500/15'}`}>
                    <GameBoard board={dispPlayer} isYourBoard={!isSpectator} onCellClick={noop} isYourTurn={false} label={isSpectator ? `🛡️ ${opponentName || t('battle.player1')}` : t('battle.yourFleet')} explosionCells={playerExplosions} lastShot={playerLastShot} />
                </div>
                <div className={`glass-card p-3 sm:p-4 transition-all animate-board-entry ${isSpectator ? '' : isMyTurn ? 'border-emerald-500/20 ring-1 ring-emerald-500/10' : ''}`}>
                    <GameBoard board={dispOpponent} isYourBoard={false} onCellClick={isSpectator ? noop : handleShoot} isYourTurn={!isSpectator && isMyTurn} label={t('battle.enemyWaters', opponentName || t('battle.player2'))} explosionCells={opponentExplosions} lastShot={opponentLastShot} />
                </div>
            </div>
        </div>
    );
});

BattleField.displayName = 'BattleField';

export default BattleField;
